// ---------------------------------------------------------------------------
// Primitive checkers
// ---------------------------------------------------------------------------

/** Returns true when value is a plain string (not null, not a number, etc.). */
function isString(value) {
  return typeof value === 'string';
}

/**
 * Returns true when value represents a whole positive integer.
 * Accepts actual numbers and numeric strings (e.g. route params).
 */
function isNumericId(value) {
  if (value === null || value === undefined || value === '') return false;
  const n = Number(value);
  return Number.isFinite(n) && Number.isInteger(n) && n > 0;
}

/**
 * Returns true when value is a syntactically valid e-mail address.
 * Uses the RFC 5321 practical limit of 254 characters and a permissive but
 * realistic local-part / domain pattern.
 */
function isValidEmail(value) {
  // Basic structure: local@domain.tld
  // Allows plus-addressing, hyphens, dots, and subdomains.
  const EMAIL_RE =
    /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;
  return EMAIL_RE.test(value);
}

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

