/**
 * Validation helper module.
 *
 * Each validator returns an object:
 *   { valid: true }                      – all checks passed
 *   { valid: false, errors: [string] }   – one or more failures
 *
 * The higher-level helpers (validateCreateUser, validateUpdateUser,
 * validateIdParam) compose the field-level validators and are used
 * directly in route handlers.
 */

'use strict';

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

/**
 * Validate an `id` value (route param or body field).
 * Accepts a string or number; the value must parse as a positive integer.
 *
 * @param {*}      value
 * @param {string} [fieldName='id']
 * @returns {{ valid: boolean, errors?: string[] }}
 */
function validateId(value, fieldName = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
    return { valid: false, errors };
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0 || String(value).trim() !== String(num)) {
    errors.push(`"${fieldName}" must be a positive integer`);
  }

  return errors.length ? { valid: false, errors } : { valid: true };
}

/**
 * Validate a `name` string field.
 * Rules: required, must be a string, length 1–100 characters.
 *
 * @param {*}      value
 * @param {string} [fieldName='name']
 * @returns {{ valid: boolean, errors?: string[] }}
 */
function validateName(value, fieldName = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${fieldName}" is required`);
    return { valid: false, errors };
  }

  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return { valid: false, errors };
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`"${fieldName}" must be at least 1 character long`);
  } else if (trimmed.length > 100) {
    errors.push(`"${fieldName}" must be at most 100 characters long`);
  }

  return errors.length ? { valid: false, errors } : { valid: true };
}

/**
 * Validate an `email` string field.
 * Rules: required, must be a string, match a valid e-mail format (RFC 5321
 * simplified), max 254 characters (RFC 5321 §4.5.3.1.3).
 *
 * @param {*}      value
 * @param {string} [fieldName='email']
 * @returns {{ valid: boolean, errors?: string[] }}
 */
function validateEmail(value, fieldName = 'email') {
  // Simplified but robust e-mail regex:
  //   local part: printable characters excluding whitespace and @
  //   domain:     one or more labels separated by dots, each alphanumeric
  //               (plus hyphens), ending in a TLD of 2–63 characters
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[a-zA-Z]{2,63}$/;

  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${fieldName}" is required`);
    return { valid: false, errors };
  }

  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return { valid: false, errors };
  }

  if (value.length > 254) {
    errors.push(`"${fieldName}" must be at most 254 characters long`);
  }

  if (!EMAIL_RE.test(value)) {
    errors.push(`"${fieldName}" must be a valid email address`);
  }

  return errors.length ? { valid: false, errors } : { valid: true };
}

// ---------------------------------------------------------------------------
// Higher-level request validators
// ---------------------------------------------------------------------------

/**
 * Validate the route parameter object for endpoints that include `:id`.
 * Expects `params` to be the Express `req.params` object.
 *
 * @param {{ id?: * }} params
 * @returns {{ valid: boolean, errors?: string[] }}
 */
function validateIdParam(params = {}) {
  return validateId(params.id, 'id');
}

/**
 * Validate the request body for POST /users (create).
 * Required fields: name, email.
 *
 * @param {object} body - Express req.body
 * @returns {{ valid: boolean, errors?: string[] }}
 */
function validateCreateUser(body = {}) {
  const errors = [];

  const nameResult = validateName(body.name);
  if (!nameResult.valid) errors.push(...nameResult.errors);

  const emailResult = validateEmail(body.email);
  if (!emailResult.valid) errors.push(...emailResult.errors);

  return errors.length ? { valid: false, errors } : { valid: true };
}

/**
 * Validate both the route param and request body for PUT /users/:id (update).
 * Required: numeric id in params; at least one of name or email in body (both
 * are validated if present).
 *
 * @param {{ id?: * }} params - Express req.params
 * @param {object}     body   - Express req.body
 * @returns {{ valid: boolean, errors?: string[] }}
 */
function validateUpdateUser(params = {}, body = {}) {
  const errors = [];

  const idResult = validateId(params.id, 'id');
  if (!idResult.valid) errors.push(...idResult.errors);

  const hasName  = body.name  !== undefined && body.name  !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('request body must include at least one of "name" or "email"');
  } else {
    if (hasName) {
      const nameResult = validateName(body.name);
      if (!nameResult.valid) errors.push(...nameResult.errors);
    }

    if (hasEmail) {
      const emailResult = validateEmail(body.email);
      if (!emailResult.valid) errors.push(...emailResult.errors);
    }
  }

  return errors.length ? { valid: false, errors } : { valid: true };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Field-level (useful for unit tests and custom compositions)
  validateId,
  validateName,
  validateEmail,
  // Request-level (used directly in route handlers)
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
};

