  validateUserBody,
  validateUserIdParam,
  validateUserIdAndBody,
} = require('./validation');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// In-memory user store (seeded with initial data)
// ---------------------------------------------------------------------------
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// Health check
// ---------------------------------------------------------------------------

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ---------------------------------------------------------------------------
// GET /users — list all users (no body validation needed)
// ---------------------------------------------------------------------------

app.get('/users', (req, res) => {
  res.json(users);
});

// ---------------------------------------------------------------------------
// GET /users/:id — fetch a single user
// ---------------------------------------------------------------------------

app.get('/users/:id', (req, res) => {
  const { valid, errors } = validateUserIdParam(req.params);
  if (!valid) {
    return res.status(400).json({ errors });
  }

  const id = Number(req.params.id);
  const user = users.find((u) => u.id === id);
  if (!user) {
    return res.status(404).json({ errors: [`user with id ${id} not found`] });
  }

  res.json(user);
});

// ---------------------------------------------------------------------------
// POST /users — create a new user
// ---------------------------------------------------------------------------

app.post('/users', (req, res) => {
  const { valid, errors } = validateUserBody(req.body);
  if (!valid) {
    return res.status(400).json({ errors });
  }

  const newUser = {
    id: nextId++,
    name: req.body.name.trim(),
    email: req.body.email,
  };
  users.push(newUser);
  res.status(201).json(newUser);
});

// ---------------------------------------------------------------------------
// PUT /users/:id — replace an existing user
// ---------------------------------------------------------------------------

app.put('/users/:id', (req, res) => {
  const { valid, errors } = validateUserIdAndBody(req.params, req.body);
  if (!valid) {
    return res.status(400).json({ errors });
  }

  const id = Number(req.params.id);
  const index = users.findIndex((u) => u.id === id);
  if (index === -1) {
    return res.status(404).json({ errors: [`user with id ${id} not found`] });
  }

  users[index] = { id, name: req.body.name.trim(), email: req.body.email };
  res.json(users[index]);
});

// ---------------------------------------------------------------------------
// DELETE /users/:id — remove a user
// ---------------------------------------------------------------------------

app.delete('/users/:id', (req, res) => {
  const { valid, errors } = validateUserIdParam(req.params);
  if (!valid) {
    return res.status(400).json({ errors });
  }

  const id = Number(req.params.id);
  const index = users.findIndex((u) => u.id === id);
  if (index === -1) {
    return res.status(404).json({ errors: [`user with id ${id} not found`] });
  }

  users.splice(index, 1);
  res.status(204).send();
});

// ---------------------------------------------------------------------------

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

